/**
 * Generates per-service `buf.yaml` (lint + breaking config) and
 * `buf.gen.yaml` (codegen plugins) alongside the emitted `.proto` tree.
 *
 * Output is deterministic: keys in a fixed canonical order, two-space indent,
 * trailing newline. No external YAML dependency — the shapes are small and
 * fixed enough to render directly.
 */

/** The header marker written on every generated buf config. */
export const BUF_HEADER_MARKER =
  "# Generated by @qninhdt/typespec-protobuf-openlet. Edit at your own risk.";
export const BUF_HEADER_OPTOUT = "# Remove this line to mark the file hand-managed and stop regen.";

export type BufPlugin = "go" | "go-grpc" | "python" | "grpc-python" | "pyi";

export interface BufConfigOptions {
  /** Managed-mode go_package prefix (Go services). */
  goPackagePrefix?: string;
  /** Plugins to emit in buf.gen.yaml, in the given order. */
  plugins?: BufPlugin[];
  /** Output subdirectory for generated stubs. Default "gen". */
  out?: string;
  /** Lint rule names to except (added to the defaults). */
  lintExcept?: string[];
  /** File paths to ignore for lint. */
  lintIgnore?: string[];
  /** buf-breaking path ignores (intentional file relocations). */
  breakingIgnore?: string[];
  /** Cross-module buf dependencies (Red Team D4). */
  deps?: string[];
}

const DEFAULT_LINT_EXCEPT = [
  "PACKAGE_VERSION_SUFFIX",
  "PACKAGE_DIRECTORY_MATCH",
  "RPC_RESPONSE_STANDARD_NAME",
  "RPC_REQUEST_STANDARD_NAME",
  "RPC_REQUEST_RESPONSE_UNIQUE",
];

/**
 * Build a `buf.yaml` (v1) string. Lint excepts default to the openlet set;
 * caller-supplied `lintExcept` entries are appended (deduped, sorted).
 */
export function buildBufYaml(opts: BufConfigOptions = {}): string {
  const lines: string[] = [BUF_HEADER_MARKER, BUF_HEADER_OPTOUT, "version: v1"];

  // breaking
  lines.push("breaking:");
  lines.push("  use:");
  lines.push("    - FILE");
  if (opts.breakingIgnore && opts.breakingIgnore.length > 0) {
    lines.push("  ignore:");
    for (const p of [...opts.breakingIgnore].sort()) lines.push(`    - ${p}`);
  }

  // lint
  lines.push("lint:");
  lines.push("  use:");
  lines.push("    - DEFAULT");
  const except = dedupeSort([...DEFAULT_LINT_EXCEPT, ...(opts.lintExcept ?? [])]);
  lines.push("  except:");
  for (const r of except) lines.push(`    - ${r}`);
  if (opts.lintIgnore && opts.lintIgnore.length > 0) {
    lines.push("  ignore:");
    for (const p of [...opts.lintIgnore].sort()) lines.push(`    - ${p}`);
  }

  // deps
  const deps = opts.deps ?? [];
  if (deps.length > 0) {
    lines.push("deps:");
    for (const d of [...deps].sort()) lines.push(`  - ${d}`);
  } else {
    lines.push("deps: []");
  }

  return lines.join("\n") + "\n";
}

/**
 * Build a `buf.gen.yaml` (v1) string for the requested plugins. Go plugins
 * emit a `managed` block with the go_package_prefix; Python plugins omit it.
 */
export function buildBufGenYaml(opts: BufConfigOptions = {}): string {
  const plugins = opts.plugins ?? ["go", "go-grpc"];
  const out = opts.out ?? "gen";
  const lines: string[] = [BUF_HEADER_MARKER, BUF_HEADER_OPTOUT, "version: v1"];

  const hasGo = plugins.some((p) => p === "go" || p === "go-grpc");
  if (hasGo && opts.goPackagePrefix) {
    lines.push("managed:");
    lines.push("  enabled: true");
    lines.push("  go_package_prefix:");
    lines.push(`    default: ${opts.goPackagePrefix}`);
  }

  lines.push("plugins:");
  for (const plugin of plugins) {
    lines.push(`  - plugin: ${plugin}`);
    lines.push(`    out: ${pluginOut(plugin, out)}`);
    const optLines = pluginOpts(plugin);
    if (optLines.length === 1) {
      lines.push(`    opt: ${optLines[0]}`);
    } else if (optLines.length > 1) {
      lines.push("    opt:");
      for (const o of optLines) lines.push(`      - ${o}`);
    }
  }

  return lines.join("\n") + "\n";
}

function pluginOut(plugin: BufPlugin, out: string): string {
  switch (plugin) {
    case "go":
    case "go-grpc":
      return `${out}/go`;
    case "python":
    case "grpc-python":
    case "pyi":
      return `${out}/python`;
  }
}

function pluginOpts(plugin: BufPlugin): string[] {
  switch (plugin) {
    case "go":
      return ["paths=source_relative"];
    case "go-grpc":
      return ["paths=source_relative", "require_unimplemented_servers=false"];
    default:
      return [];
  }
}

function dedupeSort(items: string[]): string[] {
  return [...new Set(items)].sort();
}

/**
 * True when an existing buf config file is safe to overwrite — i.e. it still
 * carries the generated header marker. A file whose marker was removed is
 * treated as hand-managed and left untouched (best-effort, Red Team S4).
 */
export function isRegenerable(existingContent: string | undefined): boolean {
  if (existingContent === undefined) return true; // no file yet
  return existingContent.includes(BUF_HEADER_MARKER);
}
